import { impuestos } from "@/constants/impuestos";
import { cotizadorEngine } from "../cotizadorEngine";

describe("cotizadorEngine", () => {
  it("debe calcular subtotal, IVA y total de todos los items", () => {
    const resultado = cotizadorEngine({
      items: [
        { cantidad: 2, precioUnitario: 10000 },
        { cantidad: 1, precioUnitario: 5000 },
      ],
    });

    expect(resultado).toEqual({
      cantidadItems: 2,
      subtotal: 25000,
      iva: 25000 * impuestos.iva,
      total: 25000 + 25000 * impuestos.iva,
    });
  });

  it("debe retornar totales en cero si no hay items", () => {
    expect(cotizadorEngine({ items: [] })).toEqual({
      cantidadItems: 0,
      subtotal: 0,
      iva: 0,
      total: 0,
    });
  });

  it("debe lanzar error si un item tiene precio negativo", () => {
    expect(() =>
      cotizadorEngine({
        items: [{ cantidad: 1, precioUnitario: -1000 }],
      })
    ).toThrow("El precio unitario no puede ser negativo");
  });
});
